def get_invalid_characters(value):
    value = value.replace(' ', '')
    len_v = len(value)
    arg = ['a', 'b', 'c', 'd', 'e', 'x', 'y', 'h', 'i', 'k']
    oper = ['+', '-', '*', '/', '%', '^']

    for i in range(len_v):
        s = value[i]

        if s == '.':
            if i - 1 < 0 or i + 1 >= len_v or not value[i - 1].isnumeric() or not value[i + 1].isnumeric():
                return False

        if s == '(':
            if i > 0 and value[i - 1] not in oper + ['(']:
                return False
            if i < len_v - 1 and value[i + 1] not in arg + ['('] and not value[i + 1].isnumeric():
                return False

        if s == ')':
            if i > 0 and value[i - 1] not in arg + [')'] and not value[i - 1].isnumeric():
                return False
            if i < len_v - 1 and not value[i + 1].isnumeric() and value[i + 1] not in oper + [')']:
