def is_embargoed(embargo_date, accessright=None):
    """Test if date is still embargoed (according to UTC date."""
    if accessright not in {None, AccessRight.EMBARGOED}:
        return False
    return AccessRight.is_embargoed(embargo_date) if embargo_date is not None else False

