def _unbundle(self, decoded):
    """Recursive bundle-unpacking function"""

    if decoded[0] != "#bundle":
        self.replies += self.server.dispatchMessage(decoded[0], decoded[1][1:], decoded[2:], self.client_address)
        return

    now = time.time()
    timetag = decoded[1]
    if 0. < timetag > now:
        time.sleep(timetag - now)

    for msg in decoded[2:]:
        self._unbundle(msg)

