    if keystate[pg.K_UP]:
        self.vy = -5
    if keystate[pg.K_DOWN]:
        self.vy = 5
    if keystate[pg.K_LEFT]:
        self.vx = -5
    if keystate[pg.K_RIGHT]:
        self.vx = 5
    if 0 != self.vx != 0 and 0 != self.vy != 0:
        self.vx *= 0.7071
        self.vy *= 0.7071
